(1712, 1, '2026-03-24 16:54:49', '2026-03-24 16:54:49', '<h1>Contact Us</h1>				\n					<h2>Get In Touch</h2>				\n		[sureforms id=\\\"2395\\\"]		\n					<h2>Talk To Us</h2>				\n				<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" xmlns:xlink=\\\"http://www.w3.org/1999/xlink\\\" width=\\\"42\\\" height=\\\"42\\\" viewBox=\\\"0 0 42 42\\\"><g id=\\\"Group_168\\\" data-name=\\\"Group 168\\\" transform=\\\"translate(-912 -872)\\\"><g id=\\\"Ellipse_2\\\" data-name=\\\"Ellipse 2\\\" transform=\\\"translate(912 872)\\\" fill=\\\"#fff\\\" stroke=\\\"#74a84a\\\" stroke-linejoin=\\\"round\\\" stroke-width=\\\"1\\\"><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"21\\\" stroke=\\\"none\\\"></circle><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"20.5\\\" fill=\\\"none\\\"></circle></g><image id=\\\"mail\\\" width=\\\"18\\\" height=\\\"18\\\" transform=\\\"translate(924 884)\\\" xlink:href=\\\"data:image/png;base64,\\\"></image></g></svg>				\n									<h3>\n							EMAIL						\n					</h3>\n									<p>\n						something@tyler.com\n					</p>\n				<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" xmlns:xlink=\\\"http://www.w3.org/1999/xlink\\\" width=\\\"42\\\" height=\\\"42\\\" viewBox=\\\"0 0 42 42\\\"><g id=\\\"Group_169\\\" data-name=\\\"Group 169\\\" transform=\\\"translate(-912 -992)\\\"><g id=\\\"Ellipse_2_copy\\\" data-name=\\\"Ellipse 2 copy\\\" transform=\\\"translate(912 992)\\\" fill=\\\"#fff\\\" stroke=\\\"#74a84a\\\" stroke-linejoin=\\\"round\\\" stroke-width=\\\"1\\\"><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"21\\\" stroke=\\\"none\\\"></circle><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"20.5\\\" fill=\\\"none\\\"></circle></g><image id=\\\"phone-call_2_\\\" data-name=\\\"phone-call (2)\\\" width=\\\"19\\\" height=\\\"19\\\" transform=\\\"translate(924 1004)\\\" xlink:href=\\\"data:image/png;base64,\\\"></image></g></svg>				\n									<h3>\n							PHONE NUMBER						\n					</h3>\n									<p>\n						202-555-0188					</p>\n				<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" xmlns:xlink=\\\"http://www.w3.org/1999/xlink\\\" width=\\\"42\\\" height=\\\"42\\\" viewBox=\\\"0 0 42 42\\\"><g id=\\\"Group_170\\\" data-name=\\\"Group 170\\\" transform=\\\"translate(-912 -1122)\\\"><g id=\\\"Ellipse_2_copy_2\\\" data-name=\\\"Ellipse 2 copy 2\\\" transform=\\\"translate(912 1122)\\\" fill=\\\"#fff\\\" stroke=\\\"#74a84a\\\" stroke-linejoin=\\\"round\\\" stroke-width=\\\"1\\\"><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"21\\\" stroke=\\\"none\\\"></circle><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"20.5\\\" fill=\\\"none\\\"></circle></g><image id=\\\"location\\\" width=\\\"25\\\" height=\\\"25\\\" transform=\\\"translate(921 1131)\\\" xlink:href=\\\"data:image/png;base64,\\\"></image></g></svg>				\n									<h3>\n							ADDRESS						\n					</h3>\n									<p>\n						2727 Ocean Road,<br />\nMalibu, CA, 90264\n					</p>\n					<h4>Follow Us:</h4>				\n					<a target=\\\"_blank\\\">\n						Facebook-f\n											</a>\n					<a target=\\\"_blank\\\">\n						Twitter\n											</a>\n					<a target=\\\"_blank\\\">\n						Linkedin-in\n											</a>\n					<a target=\\\"_blank\\\">\n						Play\n											</a>', 'Liên hệ', '', 'publish', 'closed', 'closed', '', 'contact', '', '', '2026-03-24 17:07:41', '2026-03-24 17:07:41', '', 0, 'http://localhost/thaolinhmateco/contact/', 0, 'page', '', 0);
