\"http://www.w3.org/1999/xlink\\\" width=\\\"42\\\" height=\\\"42\\\" viewBox=\\\"0 0 42 42\\\"><g id=\\\"Group_170\\\" data-name=\\\"Group 170\\\" transform=\\\"translate(-912 -1122)\\\"><g id=\\\"Ellipse_2_copy_2\\\" data-name=\\\"Ellipse 2 copy 2\\\" transform=\\\"translate(912 1122)\\\" fill=\\\"#fff\\\" stroke=\\\"#74a84a\\\" stroke-linejoin=\\\"round\\\" stroke-width=\\\"1\\\"><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"21\\\" stroke=\\\"none\\\"></circle><circle cx=\\\"21\\\" cy=\\\"21\\\" r=\\\"20.5\\\" fill=\\\"none\\\"></circle></g><image id=\\\"location\\\" width=\\\"25\\\" height=\\\"25\\\" transform=\\\"translate(921 1131)\\\" xlink:href=\\\"data:image/png;base64,\\\"></image></g></svg>				\n									<h3>\n							ADDRESS						\n					</h3>\n									<p>\n						2727 Ocean Road,<br />\nMalibu, CA, 90264\n					</p>\n					<h4>Follow Us:</h4>				\n					<a target=\\\"_blank\\\">\n						Facebook-f\n											</a>\n					<a target=\\\"_blank\\\">\n						Twitter\n											</a>\n					<a target=\\\"_blank\\\">\n						Linkedin-in\n											</a>\n					<a target=\\\"_blank\\\">\n						Play\n											</a>', 'Liên hệ', '', 'inherit', 'closed', 'closed', '', '1712-revision-v1', '', '', '2026-03-24 17:07:41', '2026-03-24 17:07:41', '', 1712, 'http://localhost/thaolinhmateco/?p=2399', 0, 'revision', '', 0);
